function handleKeyDown(e: React.KeyboardEvent<HTMLDivElement>): void {
  if (mention.open) {
    if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
      e.preventDefault()
      mention.onKeyDown(e)
      return
    }
    if (e.key === 'Enter' || e.key === 'Tab') {
      e.preventDefault()
      const file = mention.filteredFiles[mention.selectedIndex]
      if (file) handleMentionSelect(file)
      else mention.close()
      return
    }
    if (e.key === 'Escape') {
      e.preventDefault()
      mention.close()
      return
    }
  }
  // History navigation
  if (sentMessages.length > 0) {
    if (e.key === 'ArrowUp') {
      e.preventDefault()
      navigateHistory('up')
      return
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      navigateHistory('down')
      return
    }
  }
  // Reset history pointer on any other key (except modifiers)
  if (historyIndex !== -1 && !['Shift', 'Meta', 'Control', 'Alt'].includes(e.key)) {
    resetHistory()
  }
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault()
    handleSubmit()
  }
}

