  }, [])

  const setEditorText = useCallback((text: string): void => {
    if (!editorRef.current) return
    editorRef.current.innerHTML = ''
    if (text) {
      editorRef.current.textContent = text
    }
    // Move cursor to end
    const sel = window.getSelection()
